import { Grid, Typography, Input, Button } from "@mui/material";
import React, { FunctionComponent, useCallback, useEffect, useState } from "react";
import { Participant } from "../../components/participant";
import { PendingParticipant as ParticipantModel, VoteStatus } from "../../models";

export interface Props {
  participants: ParticipantModel[];
  onAddParticipant: (p: ParticipantModel) => void;
  onComplete: () => void;
}

export const Participants: FunctionComponent<Props> = ({
  onComplete,
  onAddParticipant,
  participants
}) => {
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [seenEmails, setSeenEmails] = useState<Record<string, boolean>>({});
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (email in seenEmails) {
      setError(`Participant with email "${email}" already added!`);
    } else {
      setError(null);
    }
  }, [email, error, seenEmails]);

  const submit = useCallback((e) => {
    (e as any).preventDefault();
    onAddParticipant({
      name,
      email,
    });
    setSeenEmails({
      ...seenEmails,
      [email]: true,
    });
    setName("");
    setEmail("");
  }, [name, email, onAddParticipant, seenEmails]);

  return (
    <form onSubmit={submit}>
      <Grid container>
        <Grid item xs={12}>
          <Typography variant="h3">
            Add participants
          </Typography>
        </Grid>
        <Grid item xs={12}>
          <Input type="text" required placeholder="Name" value={name} onChange={e => setName(e.target.value)} />
        </Grid>
        <Grid item xs={12}>
          <Input type="email" required placeholder="Email" value={email} onChange={e => setEmail(e.target.value)} />
        </Grid>
        <Grid item xs={12}>
          <Button type="submit" disabled={error !== null}>Add</Button>
        </Grid>
        {error !== null && (
          <Grid item xs={12}>
            Error: {error}
          </Grid>
        )}
        <Grid item xs={12}>
          <Typography variant="body1">
            {participants.length} participants
          </Typography>
          {participants.map(p => <Participant key={p.email} participant={p} />)}
        </Grid>
        <Button onClick={onComplete}>Next</Button>
      </Grid>
    </form>
  );
}
