import { Grid, Typography, Paper, Card, CardContent, Box, CardMedia, useTheme } from "@mui/material";
import FavoriteIcon from '@mui/icons-material/Favorite';
import React, { FunctionComponent } from "react";
import { Choice, Option } from "../models";
import { ChoiceBreakdown } from "../stats";
import { VisualBreakdown } from "./visual-breakdown";
import { EmojiEvents } from "@mui/icons-material";

export interface Props {
  option: Option<any>
  choice: Choice;
  winner?: boolean;
  breakdown?: ChoiceBreakdown;
  breakdownType?: "visual" | "nl";
}

export const RankedChoice: FunctionComponent<Props> = ({
  choice,
  option,
  winner = false,
  breakdown,
}) => {
  const theme = useTheme();

  return (
    <Card
      sx={{
        height: 180,
        display: "flex",
        justifyContent: "center",
        alignItems: "center",
        backgroundColor: winner ? theme.palette.info.light : "inherit"
      }}
    >
      <Box
        sx={{
          display: "flex",
          flexDirection: "column",
          height: "92%",
          width: "92%"
        }}
      >
        <CardContent sx={{ flex: "0 1 auto" }}>
          <Typography
            variant="h6"
            sx={{
              color: winner ? theme.palette.info.contrastText : "inherit"
            }}
          >
            {option.name}
            {winner && <EmojiEvents sx={{ color: theme.palette.warning.light }} />}
          </Typography>
        </CardContent>
        <Box sx={{ flex: "1 0 auto" }}>
          {breakdown && <VisualBreakdown {...breakdown} />}
        </Box>
      </Box>
    </Card>
  );
};
