import { useEffect, useState } from "react";
import { merge } from "lodash";
import mockResults from "../examples/example-places-mapped.json";
import { Option, OptionType, PendingOption } from "../models";

export interface IPlacesAPI {
  search(query: PlacesQuery): Promise<PendingOption<google.maps.places.PlaceResult, PlaceInfo>[]>;
  getDetails(place: google.maps.places.PlaceResult): Promise<PendingOption<google.maps.places.PlaceResult, PlaceInfo>>
}

export interface PlaceInfo {
  link?: string;
  open?: boolean;
  openingHours?: {
    weekdayText?: string[];
    periods?: {
      open?: {
        day: number;
        hours: number;
        minutes:
        number;
      }
      close?: {
        day: number;
        hours: number;
        minutes: number;
      }
    }[]
  };
  totalRatings?: number;
  rating?: number;
  priceLevel?: number;
}

export const usePlaces = () => {
  console.log(process.env.REACT_APP_ENV);
  const [api, setApi] = useState<IPlacesAPI>();

  useEffect(() => {
    if (api) return;

    if (process.env.REACT_APP_ENV === "local") {
      console.log("Using mock places API for local development");
      setApi(new MockPlaces());
      return;
    }
    
    const script = document.createElement("script");
    script.src = `https://maps.googleapis.com/maps/api/js?key=${process.env.REACT_APP_GOOGLE_API_KEY}&libraries=places&callback=initMap`;
    (window as any).initMap = function() {
      console.log("map callback called");
      const mapElement = document.createElement("div");
      const map = new google.maps.Map(mapElement);
      const placesApi = new google.maps.places.PlacesService(map);
      setApi(new PlacesApi(placesApi));
      document.body.appendChild(mapElement);
    }
    document.body.appendChild(script);
    
  });

  return api;
}

type PlacesQuery = {
  term: string;
  type: string;
  location: google.maps.LatLng | google.maps.LatLngLiteral; // TODO: get from lib
  radius: number;
}

class MockPlaces implements IPlacesAPI {
  async search(_: PlacesQuery) {
    return mockResults.map(mr => ({
      ...mr,
      type: OptionType.GOOGLE_PLACE,
      original: {
        place_id: this.fakeID()
      }
    }));
  }

  async getDetails(place: google.maps.places.PlaceResult): Promise<PendingOption<google.maps.places.PlaceResult, PlaceInfo>> {
    return {
      ...place,
      img: "https://www.tomatotimers.com/assets/images/tomato-work-flow.svg",
      description: "fake data about a mock place",
      uri: "https://www.place.com",
      name: "FAKE PLACE",
      original: {},
      type: OptionType.GOOGLE_PLACE,
      info: {
        link: "https://www.place.com",
        open: true,
        openingHours: {
          weekdayText: ["Monday", "Tuesday"],
          periods: [{ open: { day: 0, hours: 4, minutes: 5 } }]
        },
        totalRatings: 69,
        rating: 4.2,
        priceLevel: 3
      }
    }
  }

  fakeID(): string {
    const chars = "abcdefghijklmnopqrstuvqxyz123456789";
    return [...Array(20)]
      .map(_ => chars.charAt(Math.floor(Math.random() * chars.length)))
      .join("");
  }
}

class PlacesApi implements IPlacesAPI {
  private _service: google.maps.places.PlacesService;
  constructor(service: google.maps.places.PlacesService) {
    this._service = service;
  }

  async search(query: PlacesQuery): Promise<PendingOption<google.maps.places.PlaceResult, PlaceInfo>[]> {
    return new Promise((res, rej) => {
      this._service.nearbySearch({
        type: query.type,
        keyword: query.term,
        location: query.location,
        rankBy: google.maps.places.RankBy.PROMINENCE,
        radius: query.radius
      }, (results, status) => {
        if (
          status !== google.maps.places.PlacesServiceStatus.OK &&
          status !== google.maps.places.PlacesServiceStatus.ZERO_RESULTS
        ) {
          return rej(status);
        }

        const mapped = results?.map(place => placeToOption(place)) || [];

        res(mapped);
      })
    });
  }

  async getDetails(place: google.maps.places.PlaceResult): Promise<PendingOption<google.maps.places.PlaceResult, PlaceInfo>> {
    const details: google.maps.places.PlaceResult = await new Promise((res, rej) => {
      this._service.getDetails({
        placeId: place.place_id!,
        fields: ['rating', 'price_level', 'user_ratings_total', 'website', 'opening_hours']
      }, (response, status) => {
        if (status !== google.maps.places.PlacesServiceStatus.OK) {
          return rej(status);
        }

        res(response as google.maps.places.PlaceResult);
      });
    });

    const merged = merge(place, details);

    return placeToOption(merged);
  }
}

const placeToOption = (place: google.maps.places.PlaceResult): PendingOption<google.maps.places.PlaceResult, PlaceInfo> => ({
  name: place.name || "NAME NOT FOUND",
  description: "TODO: place description",
  uri: place.website || "TODO: get uri",
  img: getImg(place.photos) || "TODO: data url for placeholder",
  info: mapInfoItems(place),
  original: place,
  type: OptionType.GOOGLE_PLACE,
});

const getImg = (options: google.maps.places.PlacePhoto[] | undefined) => {
  if (!options || options.length === 0) return;

  return options[0].getUrl();
};

const mapInfoItems = (place: google.maps.places.PlaceResult): PlaceInfo => {
  const info: PlaceInfo = {};
  const openStatus = place.opening_hours?.isOpen();
  const knowOpen = typeof openStatus === "boolean";

  if (knowOpen) {
    info.open = openStatus;
  }

  if (place.opening_hours?.periods) {
    info.openingHours = {
      weekdayText: place.opening_hours.weekday_text,
      periods: place.opening_hours.periods,
    };
  }

  info.totalRatings = place.user_ratings_total;

  info.rating = place.rating;

  info.priceLevel = place.price_level;

  info.link = place.website;

  return info;
};

const days = [ // BIG TODO: get index offset from google docs!
  "Sun",
  "Mon",
  "Tue",
  "Wed",
  "Thu",
  "Fri",
  "Sat"
];

const fmt24 = (hhmm: string): string => {
  const [hh, mm] = [hhmm.slice(0, 2), hhmm.slice(2)];
  const hhInt = parseInt(hh);
  const modded = hhInt % 12;
  const amPm = hhInt >= 12 ? "pm" : "am";

  return `${modded}:${mm} ${amPm}`;
}

const fmtTime = (time: google.maps.places.PlaceOpeningHoursTime) => {

  return `${days[time.day]} ${fmt24(time.time)}`;
}