export class Counter {
  private _counts: { [key: string | number]: number };

  constructor() {
    this._counts = {};
  }

  public inc(key: string | number) {
    if (key in this._counts) {
      this._counts[key]++;
    } else {
      this._counts[key] = 1;
    }

    return this;
  }

  public count(key: string | number) {
    if (key in this._counts) {
      return this._counts[key];
    }

    return 0;
  }

  // entries with counts in descending order
  public results(): [string, number][] {
    const items = Object.entries(this._counts);
    const sorted = items.sort(([_, countA], [__, countB]) => countA > countB ? -1 : 1);
    return sorted;
  }
}