import { Alert, Typography } from '@mui/material';
import React, { useCallback, useEffect, useState } from 'react';
import { GoogleSearch } from "./google-search";
import { PlacesSearch } from "./places-search";
import { ManualOptions } from './manual';
import { PollInfo, Info } from "./poll-info";
import { Participants } from "./participants";
import { SelectOptionsType } from "./options-type";
import { PendingOption, PendingParticipant, PendingPoll } from "../../models";
import { GroupthinkClient } from '../../client/groupthink';
import { useNavigate } from 'react-router-dom';
import { Layout } from '../../components/layout';
import { Spinner } from '../../components/spinner';

export enum Step {
  SEARCH_TYPE,
  OPTIONS,
  POLL_INFO,
  PARTICIPANTS,
}

const STEPS = [Step.SEARCH_TYPE, Step.OPTIONS, Step.POLL_INFO, Step.PARTICIPANTS];

export enum OptionsType {
  PLACES,
  GOOGLE,
  MANUAL
}

const groupthink = new GroupthinkClient();

export function CreateRoute() {
  const navigate = useNavigate();
  const [submitting, setSubmitting] = useState(false);
  const [step, setStep] = useState(Step.SEARCH_TYPE);
  const [optionsType, setOptionsType] = useState<OptionsType>();
  const [options, setOptions] = useState<PendingOption<any, any>[]>([]);
  const [info, setInfo] = useState<Info | null>(null);
  const [participants, setParticipants] = useState<PendingParticipant[]>([]);

  useEffect(() => {
    if (!info) {
      return;
    }
    if (participants.find(p => p.email === info?.ownerEmail)) {
      return;
    }
    const owner: PendingParticipant = {
      email: info.ownerEmail,
      name: info.ownerName,
    }
    setParticipants([...participants, owner]);
  }, [info, participants]);

  const next = useCallback(async () => {
    const stepIdx = STEPS.indexOf(step);
    if (stepIdx < STEPS.length - 1) {
      setStep(STEPS[stepIdx + 1]);

      return;
    }

    // time to create!
    const poll: PendingPoll = {
      owner: {
        email: info?.ownerEmail!,
        name: info?.ownerName!
      },
      name: info?.name!,
      description: info?.description!,
      participants,
      optionsList: options,
    }

    setSubmitting(true);
    const res = await groupthink.createPoll(poll);

    navigate(`/invite/${res.id}`);

  }, [step, info, options, participants, navigate]);

  const onSelectOption = useCallback((opt: PendingOption<any, any>) => {
    setOptions([...options, opt]);
  }, [options]);

  // <Typography variant="h2">
  //       {options.length + " options selected"}
  //     </Typography>

  const optionStep = (optionsType: OptionsType) => {

    return (
      <>
        <Typography component="h2">
          {options.length + " options selected"}
        </Typography>
        {
          optionsType === OptionsType.GOOGLE ?
          <GoogleSearch onSelectOption={opt => onSelectOption(opt)} onComplete={next} /> :
            optionsType === OptionsType.PLACES ?
          <PlacesSearch onSelectOption={opt => onSelectOption(opt)} onComplete={next} /> :
            optionsType === OptionsType.MANUAL ?
          <ManualOptions onSelectOption={onSelectOption} onComplete={next} /> :
              <Alert color="error">ERROR: unknown searchtype: {optionsType}</Alert>
        }
      </>
    )
  }

  if (submitting) {
    return <Spinner message={`Creating poll "${info?.name || "untitled"}"`} />
  }

  return (
    <Layout>
      {step === Step.SEARCH_TYPE && <SelectOptionsType onSelectOptionsType={(ot) => { setOptionsType(ot); next(); }} />}
      {step === Step.OPTIONS && optionStep(optionsType!)}
      {step === Step.POLL_INFO && <PollInfo onSubmit={pollInfo => { setInfo(pollInfo); next(); } }/>}
      {step === Step.PARTICIPANTS &&
        <Participants
          onComplete={next}
          participants={participants}
          onAddParticipant={p => setParticipants([...participants, p])}
        />}
    </Layout>
  );
}
