import React, { FunctionComponent, useCallback, useState } from "react";
import { OptionType, PendingOption } from "../../models";
import { Button, FormControl, FormHelperText, Input, InputLabel, List, ListItem, ListItemIcon, ListItemText, Stack, Typography, useTheme } from "@mui/material";
import { Add, Create } from "@mui/icons-material";

export interface Props {
  onComplete: () => void;
  onSelectOption: (option: PendingOption<any, Record<string, string>>) => void;
}

const validUrl = (str: string) => {
  try {
    const _ = new URL(str);
    return true;
  } catch (e) {
    return false;
  }
}

export const ManualOptions: FunctionComponent<Props> = ({
  onSelectOption,
  onComplete
}) => {
  const theme = useTheme();
  const [name, setName] = useState<string>();
  const [description, setDescription] = useState<string>();
  // TODO: img, uri
  const [pendingKey, setPendingKey] = useState<string>("");
  const [pendingVal, setPendingVal] = useState("");
  const [info, setInfo] = useState<Record<string, string>>({});
  const [img, setImg] = useState<string>();

  const addPendingInfo = useCallback(() => {
    setInfo({
      ...info,
      [pendingKey]: pendingVal
    });
    setPendingKey("");
    setPendingVal("");
  }, [info, pendingKey, pendingVal]);

  const addOption = useCallback(() => {
    if (!name) {
      alert("Name is required.");
      return;
    }
    onSelectOption({
      name,
      description,
      type: OptionType.MANUAL,
      info,
      img,
      original: {}
    });
    setName("");
    setDescription("");
    setImg("");
    setInfo({});
    setPendingKey("");
    setPendingVal("");
  }, [name, description, info, onSelectOption, setInfo, img]);

  return (
    <>
      <form onSubmit={e => { e.preventDefault(); addOption() }}>
        <Stack
          spacing={theme.spacing(3)}
        >
          <FormControl>
            <InputLabel htmlFor="option-name">Name</InputLabel>
            <Input
              required
              id="option-name"
              aria-describedby="option-name-text"
              onChange={e => setName(e.target.value)}
              value={name}
            />
            <FormHelperText id="option-name-text">The name of the option</FormHelperText>
          </FormControl>

          <FormControl>
            <InputLabel htmlFor="option-description">Description</InputLabel>
            <Input
              id="option-description"
              aria-describedby="option-description-text"
              onChange={e => setDescription(e.target.value)}
              value={description}
            />
            <FormHelperText id="option-name-text">A brief description</FormHelperText>
          </FormControl>

          <FormControl>
            <InputLabel htmlFor="option-img">Image</InputLabel>
            <Input
              id="option-img"
              aria-describedby="option-img-text"
              onChange={e => setImg(e.target.value)}
              value={img}
              error={!!img && !validUrl(img)}
            />
            <FormHelperText id="option-img-text">The URL of an image you would like to associate with this option</FormHelperText>
          </FormControl>

          <List>
          {Object.entries(info).map(
              ([key, val]) => (
                <ListItem key={`${key}:${val}`}>
                  <ListItemText>{key}: {val}</ListItemText>
                </ListItem>
              )
            )}
            <ListItem>
              <Input
                onChange={(e) => setPendingKey(e.target.value)}
                value={pendingKey}
              />: 
              <Input
                onChange={(e) => setPendingVal(e.target.value)}
                value={pendingVal}
              />
              <ListItemIcon onClick={addPendingInfo}>
                <Add />
              </ListItemIcon>
            </ListItem>
          </List>

          <Button type="submit">Add option</Button>
          
        </Stack>
      </form>
      <Button onClick={onComplete}>Next</Button>
    </>
    

  );
};
