import { Choice, Option, Ranking } from "../models";
import { Counter } from "../common";
import { consensus } from "./consensus";


export type ChoiceBreakdown = {
  placements: number[];
};

export type ChoiceReport = { [optionId: string]: ChoiceBreakdown };

const withElement = <T = any>(elems: T[], idx: number, elem: T): T[] => {
  if (idx < -1 || idx >= elems.length) {
    throw new Error(`Invalid insertion idx ${idx} for list of length ${elems.length}`)
  }

  return [...elems.slice(0, idx), elem, ...elems.slice(idx+1)];
}

export const choiceBreakDown = (optionId: string, rankings: Ranking[]): ChoiceBreakdown => {
  const placements = rankings.reduce(
    (ps, current) => {
      const place = current.choices.findIndex(ch => ch.optionId === optionId);
      return withElement(ps, place, ps[place] + 1);
    }, [...Array(rankings[0].choices.length)].map(() => 0)
  );

  return {
    placements
  };
}

export const choiceBreakdowns = (rankings: Ranking[]): ChoiceReport => {
  const ids = rankings[0].choices.map(ch => ch.optionId);

  return ids.reduce(
    (report, id) => ({
      ...report,
      [id]: choiceBreakDown(id, rankings)
    }), {} as ChoiceReport
  )
};
