import { Grid, Stack, Paper, useTheme } from "@mui/material";
import React, { FunctionComponent } from "react";
import { ChoiceBreakdown } from "../stats";

type RGB = [number, number, number];

const hexToRgb = (hex: string): RGB => {
  let res: RegExpExecArray | null;
  if (hex.startsWith("rgb")) {
    res = /rgb\(\d+,\s?\d+,\s\d+\)/i.exec(hex)
  } else {
    res = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
  }
  // https://stackoverflow.com/questions/5623838/rgb-to-hex-and-hex-to-rgb
  
  if (res === null) {
    throw new Error(`Unable to parse hex to rgb: ${hex}`);
  }

  return [
    parseInt(res[1], 16),
    parseInt(res[2], 16),
    parseInt(res[3], 16)
  ]
}


const rgbStr = ([r, g, b]: RGB): string => `rgb(${r}, ${g}, ${b})`;

const addVecs = (a: number[], b: number[]): number[] =>
  a.map((n, i) => n + b[i]);

const multVec = (a: number[], amt: number) =>
  a.map(n => n * amt);

const slerpColor = (start: RGB, end: RGB, amt: number): RGB => {
  const [r1, g1, b1] = start;
  const  [r2, g2, b2] = end;

  const dot = [r1 * r2, g1 * g2, b1 * b2]
    .reduce((t, c) => t + c, 0);
  const clamped = Math.min(Math.max(dot, -1), 1);

  const theta = Math.acos(dot) * amt;
  const relativeVec = [r2 - r1, g2 - g1, b2 - b1]
    .map(n => n * dot);
  const length = Math.sqrt(
    Math.pow(relativeVec[0], 2) +
    Math.pow(relativeVec[1], 2) +
    Math.pow(relativeVec[2], 2)
  );
  const normalized = relativeVec.map(n => n / length);

  return addVecs(
    multVec(start, Math.cos(theta)),
    multVec(normalized, Math.sin(theta))
  ) as RGB;
}

