const slerpColors = (from: RGB, to: RGB, steps: number): RGB[] => {
  // https://stackoverflow.com/questions/67919193/how-does-unity-implements-vector3-slerp-exactly
  const inc = 1 / steps;

  return [...Array(steps)].map(
    (_, i) => slerpColor(from, to, i * inc)
  )
}

const lerpColor = (from: RGB, to: RGB, steps: number): RGB[] => {
  // TODO: This is stopping one step before 'to'
  const delta = from.map((ch, i) => to[i] - ch);
  const inc = delta.map(ch => ch / (steps - 1)); 

  const stops = [...Array(steps)]
    .map((_, step) => {
      const progress = inc.map(ch => ch * step);
      return from.map((ch, chIdx) => ch + progress[chIdx]);
    });

  return stops as RGB[];
}

export const VisualBreakdown: FunctionComponent<ChoiceBreakdown & { style?: React.CSSProperties}> = ({
  placements,
  style,
}) => {
  const theme = useTheme();
  const ratios = placements.map(p => p / placements.length);
  const max = Math.max(...ratios);
  const scale = 1 / max;
  const scaled = ratios.map(r => r * scale);

  const heights = scaled.map(ratio => {

    const height = `${(ratio * 100).toFixed(2)}%`;

    return height;
  });

  const winRGB = hexToRgb(theme.palette.success.main);
  const lossRGB = hexToRgb(theme.palette.error.main);

  const colors = lerpColor(winRGB, lossRGB, placements.length)
    .map(rgbStr);

  const width = `${(100 / placements.length).toFixed(2)}%`;

  return (
      <Stack
        direction="row"
        alignItems="center"
        sx={{
          width: "100%",
          height: "100%",
        }}
      >
        {heights.map(
          (height, i) => (
            <Paper
              key={i}
              style={{
                width,
                height,
                backgroundColor: colors[i]
              }}
            />
            // <div
            //   style={{
            //     width,
            //     height,
            //     backgroundColor: colors[i]
            //   }}
            // />
          )
        )}
      </Stack>        
  );
};