import React, { FunctionComponent, useCallback, useEffect, useState } from "react";
import { Alert, Button, Checkbox, CircularProgress, Dialog, Grid, Input, Paper, Stack, Typography } from "@mui/material";

import { ClientError, GroupthinkClient, isClientErr } from "../../client/groupthink";
import { Poll } from "../../models";
import { useParams } from "react-router-dom";
import { EmailInvite, createEmailInvitations } from "../../logic/email";
import { Layout } from "../../components/layout";
import { Spinner } from "../../components/spinner";
import { useTheme } from "@mui/material";
import { ContentCopy } from "@mui/icons-material";

const groupthink = new GroupthinkClient();

const InviteRoute: FunctionComponent<{}> = () => {
  const params = useParams();
  const theme = useTheme();
  const pollID = params.pollId;
  const [poll, setPoll] = useState<Poll | null>(null);
  const [error, setError] = useState<ClientError | null>(null);
  const [invites, setInvites] = useState<EmailInvite[] | null>(null);
  const [sent, setSent] = useState<Record<string, boolean>>({});
  const [linkDisplay, setLinkDisplay] = useState<string | null>(null);

  const copyLink = useCallback(async (link: string) => {
    alert(navigator.userAgent);
    await navigator.clipboard.writeText(link);
  }, []);

  useEffect(() => {
    if (!pollID) {
      alert("Could not find poll id");
    }
    const fetchPoll = async () => {
      const res = await groupthink.getPollWithTokens(pollID!);
      if (isClientErr(res)) {
        setError(res);
        console.log("ERROR", res);
        return;
      }
      setPoll(res);
      const invitations = createEmailInvitations(res);
      setInvites(invitations);
    }
    fetchPoll();
  }, [pollID]);

  if (error) {
    return (
      <Alert severity="error">
        message: {error.message || "none" },
        status: {error.status}
      </Alert>
    );
  }

  if (!poll) {
    return <Spinner />;
  }

  return (
    <Layout>
      <Grid container>
        <Grid item xs={12}>
          <Typography component="h1">
            Invite
          </Typography>
        </Grid>

        <Stack direction="column">
          {invites && invites.map(
            ({ mailto, subject, body, name, link }) => (
              <Stack direction="row">
              <div>
                <form
                  action={`mailto:${mailto}`}
                  method="get"
                  target="blank"
                  key={mailto}
                  onSubmit={e => {
                    setSent({...sent, [mailto]: true });
                  }}
                >

                  <Stack direction="row">
                    <Checkbox checked={!!sent[mailto]} value={`sent:${mailto}`} />
                    <input type="text" hidden name="subject" defaultValue={subject} />
                    <textarea hidden name="body" defaultValue={body}></textarea>
                    <Button type="submit">Invite {name}</Button>
                  </Stack>
                  
                </form>
              </div>
                
                <div>
                  <Button
                    type="button"
                    onTouchEnd={() => copyLink(link)}
                    onClick={() => setLinkDisplay(link) }
                    endIcon={<ContentCopy />}
                  >
                    
                  </Button>
                </div>
              </Stack> 
            )
          )}
        </Stack>
      </Grid>
      {linkDisplay && (
        <Dialog open={!!linkDisplay}>
          <Paper
            style={{ padding: theme.spacing(4) }}
          >
            <Stack>
              <a href={linkDisplay}>Link</a>
              <Input type="button" onClick={() => setLinkDisplay(null)} value="Close" />
            </Stack>
            
          </Paper>
        </Dialog>
      )}
    </Layout>
    
  );
}

export default InviteRoute;
